async function authenticate(account, apiClient) {
  try {
    console.error("Authenticating with Pact...");
    const challengeResponse = await apiClient.callTool("auth_get_challenge", {
      walletAddress: account.address
    });
    const { challenge } = challengeResponse;
    const signature = await account.signMessage({ message: challenge });
    const verifyResponse = await apiClient.callTool("auth_verify", {
      walletAddress: account.address,
      signature,
      challenge
    });
    apiClient.setSessionId(verifyResponse.sessionId);
    console.error(`Wallet authenticated: ${account.address}`);
    return {
      sessionId: verifyResponse.sessionId,
      walletAddress: verifyResponse.walletAddress,
      tier: verifyResponse.tier,
      isVerifier: verifyResponse.isVerifier,
      isRegistered: verifyResponse.isRegistered,
      expiresAt: verifyResponse.expiresAt
    };
  } catch (error) {
    console.error("Authentication failed:", error);
    return null;
  }
}
async function main() {
  const privateKey = process.env.PACT_WALLET_PRIVATE_KEY;
  if (!privateKey) {
    console.error("Error: PACT_WALLET_PRIVATE_KEY environment variable is required");
    process.exit(1);
  }
  const serverUrl = process.env.PACT_MCP_SERVER_URL || "http://localhost:3001";
  console.error(`Connecting to Pact MCP Server at ${serverUrl}...`);
  const apiClient = new PactApiClient({ baseUrl: serverUrl });
  const isHealthy = await apiClient.healthCheck();
  if (!isHealthy) {
    console.error(`Warning: Pact MCP Server at ${serverUrl} is not responding`);
    console.error("Some tools may not work until the server is available");
  }
  const account = (0, import_accounts.privateKeyToAccount)(privateKey);
  const rpcUrl = process.env.PACT_RPC_URL || "https://sepolia.base.org";
  const _walletClient = (0, import_viem.createWalletClient)({
    account,
    chain: import_chains.baseSepolia,
    transport: (0, import_viem.http)(rpcUrl)
  });
  authState = await authenticate(account, apiClient);
  const server = new import_server.Server(
    {
      name: "pact",
      version: "0.1.0"
    },
    {
      capabilities: {
        tools: {}
      }
    }
  );
  server.setRequestHandler(import_types.ListToolsRequestSchema, async () => {
    return { tools: TOOLS };
  });
  server.setRequestHandler(import_types.CallToolRequestSchema, async (request) => {
    const { name, arguments: args } = request.params;
    const typedArgs = args || {};
    try {
      if (name === "auth_status") {
        return {
          content: [
            {
              type: "text",
              text: JSON.stringify({
                authenticated: !!authState?.sessionId,
                walletAddress: authState?.walletAddress || account.address,
                sessionId: authState?.sessionId,
                tier: authState?.tier,
                isVerifier: authState?.isVerifier,
                isRegistered: authState?.isRegistered,
                expiresAt: authState?.expiresAt
              })
            }
          ]
        };
      }
      if (name === "get_balance") {
        const publicClient = (0, import_viem.createPublicClient)({
          chain: import_chains.baseSepolia,
          transport: (0, import_viem.http)(rpcUrl)
        });
        const balance = await publicClient.getBalance({ address: account.address });
        return {
          content: [
            {
              type: "text",
              text: JSON.stringify({
                address: account.address,
                balance: balance.toString(),
                balanceFormatted: (0, import_viem.formatEther)(balance),
                symbol: "ETH",
                decimals: 18
              })
            }
          ]
        };
      }
      if (name === "get_profile") {
        const publicClient = (0, import_viem.createPublicClient)({
          chain: import_chains.baseSepolia,
          transport: (0, import_viem.http)(rpcUrl)
        });
        const addresses = getContractAddresses(import_chains.baseSepolia.id);
        const targetAddress = typedArgs.address || account.address;
        const isRegistered = await publicClient.readContract({
          address: addresses.agentAdapter,
          abi: PactAgentAdapterABI,
          functionName: "isRegistered",
          args: [targetAddress]
        });
        if (!isRegistered) {
          return {
            content: [
              {
                type: "text",
                text: JSON.stringify({
                  address: targetAddress,
                  isRegistered: false,
                  message: "Agent not registered on-chain"
                })
              }
            ]
          };
        }
        const agentId = await publicClient.readContract({
          address: addresses.agentAdapter,
          abi: PactAgentAdapterABI,
          functionName: "getAgentId",
          args: [targetAddress]
        });
        const reputationSummary = await publicClient.readContract({
          address: addresses.agentAdapter,
          abi: PactAgentAdapterABI,
          functionName: "getReputationSummary",
          args: [targetAddress]
        });
        const [taskWins, disputeWins, disputeLosses, totalReputation] = reputationSummary;
        return {
          content: [
            {
              type: "text",
              text: JSON.stringify({
                address: targetAddress,
                isRegistered: true,
                agentId: agentId.toString(),
                reputation: totalReputation.toString(),
                taskWins: Number(taskWins),
                disputeWins: Number(disputeWins),
                disputeLosses: Number(disputeLosses),
                note: "Agent identity is ERC-721 NFT on ERC-8004 Identity Registry"
              })
            }
          ]
        };
      }
      const result = await apiClient.callTool(name, typedArgs);
      if (name === "auth_verify") {
        const verifyResult = result;
        authState = {
          sessionId: verifyResult.sessionId,
          walletAddress: verifyResult.walletAddress,
          tier: verifyResult.tier,
          isVerifier: verifyResult.isVerifier,
          isRegistered: verifyResult.isRegistered,
          expiresAt: verifyResult.expiresAt
        };
        apiClient.setSessionId(verifyResult.sessionId);
      }
      return {
        content: [
          {
            type: "text",
            text: JSON.stringify(result, null, 2)
          }
        ]
      };
    } catch (error) {
      return {
        content: [
          {
            type: "text",
            text: JSON.stringify({
              error: error instanceof Error ? error.message : "Unknown error"
            })
          }
        ],
        isError: true
      };
    }
  });
  const transport = new import_stdio.StdioServerTransport();
  await server.connect(transport);
  console.error("Pact MCP client started");
  console.error(`Server: ${serverUrl}`);
  console.error(`Wallet: ${account.address}`);
  console.error(`RPC: ${rpcUrl}`);
  console.error(`Authenticated: ${!!authState?.sessionId}`);
  if (authState?.sessionId) {
    console.error(`Session ID: ${authState.sessionId}`);
    console.error(`Tier: ${authState.tier}`);
    console.error(`Registered: ${authState.isRegistered}`);
  }
}
main().catch((error) => {
  console.error("Fatal error:", error);
  process.exit(1);
});
